        initialCode: 'def binary_search(arr, target):\n    left, right = 0, len(arr) - 1\n    steps = 0\n    \n    while left <= right:\n        steps += 1\n        mid = (left + right) // 2\n        if arr[mid] == target:\n            return mid, steps\n        elif arr[mid] < target:\n            left = mid + 1\n        else:\n            right = mid - 1\n    return -1, steps\n\nnumbers = list(range(0, 200, 2))  # [0, 2, 4, ..., 198]\nresult, steps = binary_search(numbers, 156)\nprint(f"Знайдено на позиції {result} за {steps} кроків")',
